    if (_isPlaying) {
      await _speechService.stop();
      setState(() {
        _isPlaying = false;
      });
    } else {
      final formula = _model.customFormula;
      await _speechService.speakWithFormula(
        angle: _model.angle,
        velocity: _model.velocity,
        gravity: _model.gravity,
        customFormula: formula,
        language: 'te-IN',
      );
      setState(() {
        _isPlaying = true;
      });
    }
  }

  void _onAudioComplete() {
    if (mounted) {
      setState(() {
        _isPlaying = false;
      });
    }
  }

